final:
module gray_code_counter(
  input clk,
  input rst_n,
  output reg [3:0] gray
);

  reg [3:0] unused_binary_count;

  always @(posedge clk or negedge rst_n) begin
    if (~rst_n) begin
      unused_binary_count <= 4'b0;
      gray <= 4'b0;
    end
    else begin
      unused_binary_count <= unused_binary_count + 1;
      gray <= unused_binary_count ^ (unused_binary_count >> 1);
    end
  end

endmodule
